class Solution(object):
    def maxDistinctElements(self, nums, k):
        nums.sort()
        used = set()
        for v in nums:
            # Try to assign smallest unused value in [v-k, v+k]
            # Greedy: assign the smallest available value >= v-k
            lo = v - k
            # Find smallest value >= lo not in used
            candidate = lo
            # We need the smallest value in [v-k, v+k] not yet used
            # Since we process in sorted order, used values are increasing.
            # The next available value >= lo:
            while candidate in used:
                candidate += 1
            if candidate <= v + k:
                used.add(candidate)
        return len(used)
